import{_ as t,r as o,o as p,c as e,b as n,e as i,w as l,d as s,f as c}from"./app-55c326ac.js";const u={},r=n("h1",{id:"smtplib-邮件发送模块",tabindex:"-1"},[n("a",{class:"header-anchor",href:"#smtplib-邮件发送模块","aria-hidden":"true"},"#"),s(" smtplib: 邮件发送模块")],-1),m={class:"table-of-contents"},d=c(`<h2 id="smtplib模块额常用类与方法" tabindex="-1"><a class="header-anchor" href="#smtplib模块额常用类与方法" aria-hidden="true">#</a> smtplib模块额常用类与方法</h2><ul><li><p>SMTP类定义 smtplib.SMTP(host[,port[,local_hostname[,timeout]]])，作为SMTP的构造函数。功能是与smtp服务器建立连接。连接成功，就可以向服务器发送相关请求</p></li><li><p>有： 登录 校验 发送 退出</p></li><li><p>host参数：表示 远程smtp主机地址。 如 smtp.163.com</p></li><li><p>port参数：表示 连接端口。 默认为25</p></li><li><p>local_hostname参数：作用是在本地主机的FQDN（完整域名）发送HELO/EHLO（标识用户身份）指令。</p></li><li><p>timeout参数： 为连接或尝试在多少秒超时</p></li><li><p>SMTP类具有下面方法：</p><ul><li><p>SMTP.connect([host[,port]])方法：连接远程smtp主机方法。</p><ul><li>host：为主机地址</li><li>port：为远程主机smtp端口，默认 25</li><li>也可以知己使用 host:port 形式来标识，比如： SMTP.connect(&quot;smtp.163.com&quot;,&quot;25&quot;)</li></ul></li><li><p>SMTP.login(user,password)方法，远程smtp主机的校验方法，参数为用户名密码</p><ul><li>SMTP.login(&quot;<a href="mailto:python@163.com">python@163.com</a>&quot;,&quot;123456&quot;)</li></ul></li><li><p>SMTP.sendmail(from_addr,to_addrs,msg[,mail_options,rcpt_options])方法，实现邮件的发送功能。</p><ul><li>参数依次是：发件人，收件人，邮件内容</li><li>SMTP.sendmail(&quot;<a href="mailto:python@163.com">python@163.com</a>&quot;,&quot;<a href="mailto:demo@163.com">demo@163.com</a>&quot;,body) body内容定义如下 &#39;&#39;&#39; FROM：<a href="mailto:abc@163.com">abc@163.com</a> To: <a href="mailto:demo@163.com">demo@163.com</a> subject:test mail test mail body &#39;&#39;&#39;</li></ul></li><li><p>SMTP.starttls([keyfile[,certfile]]) 启用TLS（安全传输）模式，所有SMTP指令都将加密传输。</p><ul><li>使用gmail的smtp服务时需要启动此项才能正常发送邮件。</li></ul></li><li><p>SMTP.quit() 方法，断开SMTP服务器的连接</p></li></ul></li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token comment"># 案例 使用163邮箱向QQ邮箱发送测试邮件</span>

<span class="token keyword">import</span> smtplib
<span class="token keyword">import</span> string

HOST <span class="token operator">=</span> <span class="token string">&quot;smtp.163.com&quot;</span>     <span class="token comment"># 定义smtp主机</span>
SUBJECT <span class="token operator">=</span> <span class="token string">&quot;Test email form wli&quot;</span>     <span class="token comment"># 定义邮件主题</span>
TO <span class="token operator">=</span> <span class="token string">&quot;xxxx@qq.com&quot;</span>      <span class="token comment"># 定义收件人邮件地址</span>
FROM <span class="token operator">=</span> <span class="token string">&quot;xxxx@163.com&quot;</span>      <span class="token comment"># 定义发件人的邮件地址</span>
text <span class="token operator">=</span> <span class="token string">&quot;this is a testing&quot;</span>         <span class="token comment"># 邮件的内容</span>
string <span class="token operator">=</span> <span class="token string-interpolation"><span class="token string">f&#39;&#39;&#39;FROM: </span><span class="token interpolation"><span class="token punctuation">{</span>FROM<span class="token punctuation">}</span></span><span class="token string"> 
        TO: </span><span class="token interpolation"><span class="token punctuation">{</span>TO<span class="token punctuation">}</span></span><span class="token string">
        Subject: </span><span class="token interpolation"><span class="token punctuation">{</span>SUBJECT<span class="token punctuation">}</span></span><span class="token string">
        &#39;&#39;&#39;</span></span>
<span class="token builtin">type</span><span class="token punctuation">(</span>string<span class="token punctuation">)</span>
BODY <span class="token operator">=</span> <span class="token string">&#39;&#39;</span><span class="token punctuation">.</span>join<span class="token punctuation">(</span>string<span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>BODY<span class="token punctuation">)</span>

server <span class="token operator">=</span> smtplib<span class="token punctuation">.</span>SMTP<span class="token punctuation">(</span><span class="token punctuation">)</span>                <span class="token comment"># 创建一个SMTP()对象</span>
server<span class="token punctuation">.</span>connect<span class="token punctuation">(</span>HOST<span class="token punctuation">,</span><span class="token string">&quot;25&quot;</span><span class="token punctuation">)</span>              <span class="token comment"># 通过connect方法连接smtp主机</span>
<span class="token comment"># server.starttls()                      # 启动安全传输模式</span>
server<span class="token punctuation">.</span>login<span class="token punctuation">(</span><span class="token string">&quot;xxxx@163.com&quot;</span><span class="token punctuation">,</span><span class="token string">&quot;xxxxx&quot;</span><span class="token punctuation">)</span>      <span class="token comment"># 链接到服务器</span>
server<span class="token punctuation">.</span>sendmail<span class="token punctuation">(</span>FROM<span class="token punctuation">,</span>TO<span class="token punctuation">,</span>string<span class="token punctuation">)</span>        <span class="token comment"># 发送邮件</span>
server<span class="token punctuation">.</span>quit<span class="token punctuation">(</span><span class="token punctuation">)</span>                          <span class="token comment"># 断开SMTP链接</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,3);function k(v,b){const a=o("router-link");return p(),e("div",null,[r,n("nav",m,[n("ul",null,[n("li",null,[i(a,{to:"#smtplib模块额常用类与方法"},{default:l(()=>[s("smtplib模块额常用类与方法")]),_:1})])])]),d])}const q=t(u,[["render",k],["__file","smtplib.html.vue"]]);export{q as default};
